import React, { useState } from 'react';

const QuestionCard = ({ data, onNext }) => {
  const [userCode, setUserCode] = useState(data.initialCode);
  const [feedback, setFeedback] = useState(null); // 'success', 'error', ou null

  const checkAnswer = () => {
    // Logique simplifiée pour le front : 
    // En prod, tu enverras userCode au backend pour test sur la vraie DB.
    if (userCode.trim() === data.solution.trim()) {
      setFeedback('success');
    } else {
      setFeedback('error');
    }
  };

  return (
    <div className="bg-white rounded-2xl shadow-lg border-b-4 border-gray-200 p-6">
      <div className="mb-4">
        <span className="px-3 py-1 bg-blue-100 text-blue-700 rounded-full text-sm font-bold">
          Niveau: {data.difficulty}
        </span>
        <h2 className="text-xl mt-3 font-medium text-gray-800">{data.instruction}</h2>
      </div>

      <div className="bg-gray-900 rounded-lg p-4 mb-4">
        <textarea
          value={userCode}
          onChange={(e) => setUserCode(e.target.value)}
          className="w-full bg-transparent text-green-400 font-mono focus:outline-none resize-none"
          rows="5"
        />
      </div>

      {feedback === 'success' && (
        <div className="bg-green-100 border-l-4 border-green-500 p-4 mb-4 animate-bounce">
          <p className="text-green-700 font-bold">Bien joué ! ✨</p>
          <p className="text-sm text-green-600">{data.explanation}</p>
        </div>
      )}

      <div className="flex justify-end gap-4">
        <button 
          onClick={checkAnswer}
          className="bg-green-500 hover:bg-green-600 text-white font-bold py-3 px-8 rounded-xl transition-all shadow-[0_4px_0_rgb(22,163,74)] active:shadow-none active:translate-y-1"
        >
          VÉRIFIER
        </button>
        {feedback === 'success' && (
          <button onClick={onNext} className="text-gray-500 underline">Continuer</button>
        )}
      </div>
    </div>
  );
};
